### Recording + Replay Roundtrip
```rust
#[test]
fn record_and_replay_produces_identical_execution() {
    // First: record execution
    let recorded_outcomes: Vec<Outcome<i32>>;
    let trace_path = tempfile::NamedTempFile::new().unwrap();

    {
        let recorder = TraceRecorder::new(RecorderConfig::default());
        let lab = LabRuntimeBuilder::new()
            .rng_seed(42)
            .record_trace(recorder)
            .build();

        recorded_outcomes = lab.run(|cx| async move {
            let mut results = Vec::new();

            // Complex concurrent scenario
            cx.region(|scope| async move {
                let h1 = scope.spawn(async { 1 + 1 });
                let h2 = scope.spawn(async { 2 + 2 });
                let h3 = scope.spawn(async {
                    sleep(Duration::from_millis(10)).await;
                    3 + 3
                });

                results.push(h1.join().await);
                results.push(h2.join().await);
                results.push(h3.join().await);
            }).await;

            results
        });

        lab.save_trace(trace_path.path()).unwrap();
    }

    // Second: replay execution
    {
        let trace = TraceFile::open(trace_path.path()).unwrap();
        let replay = LabRuntime::replay(trace);

        let replayed_outcomes = replay.run(|cx| async move {
            // EXACT same code as above
            let mut results = Vec::new();
            cx.region(|scope| async move {
                let h1 = scope.spawn(async { 1 + 1 });
                let h2 = scope.spawn(async { 2 + 2 });
                let h3 = scope.spawn(async {
                    sleep(Duration::from_millis(10)).await;
                    3 + 3
                });
                results.push(h1.join().await);
                results.push(h2.join().await);
                results.push(h3.join().await);
            }).await;
            results
        });

        assert_eq!(recorded_outcomes, replayed_outcomes,
            "Replay produced different outcomes!");
    }
}
