### Divergence Detection
```rust
#[test]
fn divergence_is_detected_and_reported() {
    let trace_path = tempfile::NamedTempFile::new().unwrap();

    // Record with one behavior
    {
        let lab = LabRuntimeBuilder::new()
            .rng_seed(42)
            .record_trace(TraceRecorder::new(RecorderConfig::default()))
            .build();

        lab.run(|cx| async {
            cx.spawn(async { 1 }).join().await
        });

        lab.save_trace(trace_path.path()).unwrap();
    }

    // Replay with DIFFERENT code (should diverge)
    {
        let trace = TraceFile::open(trace_path.path()).unwrap();
        let replay = LabRuntime::replay(trace);

        let result = std::panic::catch_unwind(|| {
            replay.run(|cx| async {
                // Different: spawns TWO tasks instead of one
                cx.spawn(async { 1 }).join().await;
                cx.spawn(async { 2 }).join().await;
            })
        });

        assert!(result.is_err(), "Should have detected divergence");

        // Check divergence error contains useful info
        let err = result.unwrap_err();
        let msg = err.downcast_ref::<String>().unwrap();
        assert!(msg.contains("divergence") || msg.contains("Divergence"));
    }
}
