```rust
/// End-to-end test that simulates a real debugging workflow
#[test]
fn e2e_debugging_workflow() {
    // Simulates: developer has a flaky test, uses replay to debug

    tracing_subscriber::fmt()
        .with_env_filter("trace")
        .with_test_writer()
        .init();

    tracing::info!("Starting E2E replay debugging test");

    // Step 1: Run code that occasionally fails
    let mut failure_trace = None;
    for seed in 0..100 {
        tracing::debug!(seed, "Trying seed");

        let recorder = TraceRecorder::new(RecorderConfig::default());
        let lab = LabRuntimeBuilder::new()
            .rng_seed(seed)
            .record_trace(recorder)
            .build();

        let result = lab.run(|cx| async {
            flaky_concurrent_code(&cx).await
        });

        if result.is_err() {
            tracing::info!(seed, "Found failing seed, saving trace");
            let temp = tempfile::NamedTempFile::new().unwrap();
            lab.save_trace(temp.path()).unwrap();
            failure_trace = Some((seed, temp));
            break;
        }
    }

    // Step 2: Replay the failure
    let (seed, trace_file) = failure_trace.expect("Should have found a failure");
    tracing::info!(seed, "Replaying failure");

    let trace = TraceFile::open(trace_file.path()).unwrap();
    let mut replay = LabRuntime::replay_stepping(trace);

    // Step 3: Step through execution
    let mut step_count = 0;
    while let Some(event) = replay.step() {
        step_count += 1;
        tracing::trace!(?event, step_count, "Replay step");

        // Can inspect state at each step
        let state = replay.runtime_state();
        tracing::trace!(?state.active_tasks, ?state.regions, "Runtime state");
    }

    tracing::info!(step_count, "Replay complete");
    assert!(step_count > 0, "Should have stepped through events");
}
